const evt = $('Classify Event').item.json;
const draft = $('Lookup Draft').item.json;

// Block edit path for colleague_dm — approver is requester, edit would allow social-engineering text
if (draft.content_type === 'colleague_dm') {
  return [{ json: { skip: true } }];
}

// HIGH-01: verify the edit reply author is the approver
if (evt.actor_discord_id !== draft.approver_discord_id) {
  return [{ json: { skip: true } }];
}

// MED-03: sanitize content — strip n8n expression syntax, limit length
const safe = String(evt.content ?? '')
  .replace(/\{\{/g, '{ {')
  .replace(/\$\{/g, '$ {')
  .slice(0, 2000);

return [{ json: { skip: false, safe_content: safe, message_id: evt.message_id, reply_message_id: evt.reply_id, draft_id: draft.draft_id } }];

const content = $('Classify Event').item.json.content ?? '';
const offerRow = $('Lookup Offer for Free Text').item.json;

// Match pattern: HH:MM-HH:MM (today|tomorrow)?
const match = content.match(/^(\d{1,2}):(\d{2})\s*[-–]\s*(\d{1,2}):(\d{2})(?:\s+(today|tomorrow))?/i);

if (!match) {
  return [{ json: {
    parse_ok: false,
    dm_channel_id: offerRow.dm_channel_id,
    offer_id: offerRow.offer_id
  }}];
}

const [, startH, startM, endH, endM, dayWord] = match;
const now = new Date();
const base = new Date(now.getFullYear(), now.getMonth(), now.getDate());

if (dayWord && dayWord.toLowerCase() === 'tomorrow') {
  base.setDate(base.getDate() + 1);
}

const start = new Date(base);
start.setHours(parseInt(startH, 10), parseInt(startM, 10), 0, 0);

const end = new Date(base);
end.setHours(parseInt(endH, 10), parseInt(endM, 10), 0, 0);

if (end <= start) {
  return [{ json: {
    parse_ok: false,
    dm_channel_id: offerRow.dm_channel_id,
    offer_id: offerRow.offer_id
  }}];
}

return [{ json: {
  parse_ok: true,
  start_iso: start.toISOString(),
  end_iso: end.toISOString(),
  start_label: startH.padStart(2,'0') + ':' + startM,
  end_label: endH.padStart(2,'0') + ':' + endM,
  dm_channel_id: offerRow.dm_channel_id,
  offer_id: offerRow.offer_id,
  feature_area: offerRow.feature_area,
  requester_calendar_email: offerRow.requester_calendar_email ?? ''
}}];
